tinymce.PluginManager.add('file', function(editor, url) {
    
    window.fileHandle = null;

    // Add button to toolbar
    editor.ui.registry.addButton('open', {
        text: 'Open',
        icon: "browse",
        onAction: function() {
            openFile();
        }
    });

    // Add menu item
    editor.ui.registry.addMenuItem('open', {
        text: 'Open',
        icon: "browse",
        onAction: function() {
            openFile();
        }
    });

    // Add button to toolbar
    editor.ui.registry.addButton('save', {
        text: 'Save',
        icon: "save",
        onAction: function() {
            saveFile();
        }
    });    
    
    // Add menu item
    editor.ui.registry.addMenuItem('save', {
        text: 'Save',
        icon: "save",
        shortcut: 'Ctrl+S',
        onAction: function() {
            saveFile();
        }
    });

    editor.ui.registry.addMenuItem('saveas', {
        text: 'Save As...',
        icon: "save",
        onAction: function() {
            saveFileAs();
        }
    });
    
    editor.ui.registry.addMenuItem('share', {
        text: 'Share',
        icon: 'export',
        onAction: function() {
            shareFile();
        }
    });
    
	function getWellKnownDirectory(filePath) {
		// Normalize path to lowercase for comparison
		const normalizedPath = filePath.toLowerCase();
		
		// Check for well-known directories in order of specificity
		if (normalizedPath.includes('/downloads')) {
		    return 'downloads';
		}
		if (normalizedPath.includes('/desktop')) {
		    return 'desktop';
		}
		if (normalizedPath.includes('/documents')) {
		    return 'documents';
		}
		
		// Default fallback
		return 'documents';
	}
	
    const options = {
        types: [
            {
                description: 'HTML file',
                accept: { 'text/html': ['.html', '.htm'] }
            },		        
            {
                description: 'Text file',
                accept: { 'text/plain': ['.txt'] }
            },
            {
                description: 'Markdown file',
                accept: { 'text/markdown': ['.md'] }
            },
            {
                description: 'Word Document',
                accept: { 'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx'] }
            }
        ],
        //startIn: getWellKnownDirectory(filePath),
        multiple: false,
        excludeAcceptAllOption: true
    };
	
	getFileLegacy = () => {
	  return new Promise((resolve, reject) => {
		const accept = options.types
		  .flatMap(type => Object.values(type.accept).flat())
		  .join(',');	  
		const filePicker = document.createElement('input');
		filePicker.type = 'file';
		filePicker.multiple = false;
		filePicker.accept = accept;
		
		filePicker.onchange = (e) => {
		  const file = filePicker.files[0];
		  if (file) {
		    resolve(file);
		    return;
		  }
		  reject(new Error('AbortError'));
		};

		filePicker.click();
	  });
	};
	
	const readFile = (file) => {
	  return new Promise((resolve, reject) => {
		const reader = new FileReader();
		reader.onload = (e) => resolve(e.target.result);
		reader.onerror = (e) => reject(e);
		reader.readAsText(file);
	  });
	};
	
	async function openFile(filePath) {
		try {
			let file=null;
			let content=null;
		    if (!window.showOpenFilePicker) {
		        file = await getFileLegacy();
				if (file) {
					content = await readFile(file); // reads bytes → returns string
					// console.log(content);				  
				}
		    } else {
				[fileHandle] = await window.showOpenFilePicker(options);
				const writable = await fileHandle.createWritable();
				file = await fileHandle.getFile();
				content = await file.text();
		    }
		    
			const allowed = options.types.flatMap(type => Object.values(type.accept).flat());	    
		    const extension = file.name.substring(file.name.lastIndexOf('.')).toLowerCase();
		    // console.log("file type:",extension);
			if (!allowed.includes(extension)) {
		        editor.notificationManager.open({
		            text: `File type ${extension} is not supported!`,
		            type: 'error',
		            timeout: 5000
		        });
		        return;	  
			}
			// clear current document
		    editor.execCommand('mceNewDocument');
		    // Convert to HTML based on file type
		    if (extension === '.html') {
				const parser = new DOMParser();
				const doc = parser.parseFromString(content, 'text/html');	
				const scripts = doc.querySelectorAll('script');
				scripts.forEach(script => script.remove());			    	
		    	// console.log(doc.body.innerHTML);
		    	editor.setContent(doc.body.innerHTML);
		    } else {
		    	let htmlContent;		    	
				if (extension === '.docx') {
				    // For binary files, pass the blob
				    htmlContent = await window.fileConverter.convertToHtml(file, extension);
				} else {
				    // For text files, read as text first
				    htmlContent = await window.fileConverter.convertToHtml(content, extension);
				}
				
				// Recalculate pages
				setTimeout(() => {
				    if (window.reapplyPageView) {
				        window.reapplyPageView(htmlContent);
				    }
				}, 100);		    
		    }
		    
		    document.title = file.name + '-Yadikar Text Editor';
		    window.titleUpdate.title = document.title;
		    window.currentLocalFile = {
		        handle: fileHandle,
		        name: file.name,
		        originalExtension: extension
		    };
   
		} catch (error) {
		    if (error.name !== 'AbortError') {
		        console.error('Error opening file:', error);
		        editor.notificationManager.open({
		            text: 'Failed to open file: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		    }
		}
	}
	
	async function askFileAccessPermission(editor, filePath)
	{
        const dialogConfig = {
            title: 'File Access Notification',
            body: {
                type: 'panel',
                items: [
                    {
						type: 'htmlpanel',
						html: '<p>Select the file again to open with the Yadikar Editor.</p>'
                    }
                ]
            },
		    buttons: [
		        {
		            type: 'cancel',
		            text: 'No'
		        },
		        {
		            type: 'submit',
		            text: 'OK',
		            primary: true
		        }
		    ],
		    onSubmit: async function(api) {
		    	await openFile(filePath);
		    	api.close();
		    }
        };
        var dialogInstance = editor.windowManager.open(dialogConfig);		
	}
	editor.addCommand('cmdOpenFile', function(ui, filePath) {
		askFileAccessPermission(editor, filePath);
	});
	
	async function saveFile() {
		try {
			if(!window.fileHandle) {
				if (!window.showSaveFilePicker) {
				     window.fileHandle = await getFileLegacy();
				} else {
					const options = {
						suggestedName: 'document.html',
						types: window.getFilePickerTypes(),
						excludeAcceptAllOption: true
					};
					window.fileHandle = await window.showSaveFilePicker(options);	
				}
			}
		    
		    // Get selected extension from filename
		    const fileName = window.fileHandle.name;
		    const extension = fileName.substring(fileName.lastIndexOf('.'));
		    
		    // Convert content
		    const htmlContent = editor.getContent();
		    let content;
		    
		    try {
		        content = await window.fileConverter.convert(htmlContent, extension);
		    } catch (error) {
		        editor.notificationManager.open({
		            text: 'Conversion failed: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		        return;
		    }
		    
		    if(window.showSaveFilePicker) {
		    	 const writable = await window.fileHandle.createWritable();
		    	 await writable.write(content);
		    	 await writable.close();
		    } else {
		    	await downloadFile(content);
		    }

		    window.currentLocalFile = {
		        handle: window.fileHandle,
		        name: window.fileHandle.name
		    };

		} catch (error) {
		    if (error.name !== 'AbortError') {
		        console.error('Error saving file:', error);
		        editor.notificationManager.open({
		            text: 'Failed to save file: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		    }
		}
	}

	async function saveFileAs() {
		try {
			let fileHandle = null;
			if (!window.showSaveFilePicker) {
			     fileHandle = await getFileLegacy();
			} else {
				const options = {
					suggestedName: 'document.html',
					types: window.getFilePickerTypes(),
					excludeAcceptAllOption: true
				};
				fileHandle = await window.showSaveFilePicker(options);	
			}
		    
		    // Get selected extension from filename
		    const fileName = fileHandle.name;
		    const extension = fileName.substring(fileName.lastIndexOf('.'));
		    
		    // Convert content
		    const htmlContent = editor.getContent();
		    let content;
		    
		    try {
		        content = await window.fileConverter.convert(htmlContent, extension);
		    } catch (error) {
		        editor.notificationManager.open({
		            text: 'Conversion failed: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		        return;
		    }
		    
		    if(window.showSaveFilePicker) {
		    	 const writable = await fileHandle.createWritable();
		    	 await writable.write(content);
		    	 await writable.close();
		    } else {
		    	await downloadFile(content);
		    }

		} catch (error) {
		    if (error.name !== 'AbortError') {
		        console.error('Error saving file:', error);
		        editor.notificationManager.open({
		            text: 'Failed to save file: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		    }
		}
	}
	
    // Fallback download method for unsupported browsers
	async function downloadFile(content) {
		const blob = new Blob([content], { type: 'text/html' });
		const url = URL.createObjectURL(blob);
		const a = document.createElement('a');
		a.href = url;
		a.download = 'document.html';
		document.body.appendChild(a);
		a.click();
		document.body.removeChild(a);
		URL.revokeObjectURL(url);

		editor.notificationManager.open({
		    text: 'File downloaded',
		    type: 'success',
		    timeout: 3000
		});
	}

	async function shareFile() {
		// Check if sharing files is supported
		if (navigator.canShare) {
			// Create file content
			const htmlContent = editor.getContent();
			let content;
		    try {
		        content = await window.fileConverter.convert(htmlContent, '.html');
		    } catch (error) {
		        editor.notificationManager.open({
		            text: 'Conversion failed: ' + error.message,
		            type: 'error',
		            timeout: 5000
		        });
		        return;
		    }
			const blob = new Blob([content], { type: 'text/html' });		

			// Create a File object
			const file = new File([blob], "document.html", {
				type: "text/html",
				lastModified: new Date().getTime()
			});		
			try {
			  await navigator.share({
				title: "My Shared File",
				text: "Check out this document!",
				files: [file]
			  });
			  console.log("File shared successfully");
			} catch (err) {
			  console.error("Share failed:", err.message);
			}
		} else {
	        editor.notificationManager.open({
	            text: 'File sharing not supported in your browser!',
	            type: 'error',
	            timeout: 5000
	        });			
		}	
	}
	
	editor.on('init', function() {
		editor.saveFile = saveFile;
	});

	// unsaved change handler
	editor.on('dirty', function() {
		// Your custom function here
		// console.log('Editor is now dirty');
		window.titleUpdate.addUnsavedMsg();
	});
	
	// autosave handler
	editor.on('StoreDraft', function() {
		if(window.fileHandle && editor.isDirty()) {
			editor.execCommand('mceSave'); // or your custom save logic
		}
		window.titleUpdate.addSavedMsg();
	});	
	
    return {
        getMetadata: function() {
            return {
                name: 'Open from Computer',
                url: 'http://yoursite.com'
            };
        }
    };
});
